"use client"

import Lottie from "lottie-react"
import explorerAnimation from "@/assets/animations/explorer-walking.json"
import { motion, useAnimationControls } from "framer-motion"
import { useEffect, useRef, useState } from "react"

export default function AnimatedHeader() {
  const [showText, setShowText] = useState(false)
  const controls = useAnimationControls()
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!containerRef.current) return

    const containerWidth = containerRef.current.offsetWidth
    const detectiveWidth = 96 // assuming 6rem (w-24) for the Lottie

    // Animate detective across the full container width
    controls.start({
      x: containerWidth - detectiveWidth,
      transition: { duration: 2.8, ease: "easeInOut" },
    }).then(() => {
      setShowText(true) // trigger title/desc fade-in
    })
  }, [])

  return (
    <div
      ref={containerRef}
      className="relative w-full mb-8 h-28 flex items-center justify-between overflow-hidden"
    >
      {/* Detective Animation */}
      <motion.div
        className="absolute left-0 top-0 w-24 h-24 z-10"
        initial={{ x: 0 }}
        animate={controls}
      >
        <Lottie animationData={explorerAnimation} loop={false} />
      </motion.div>

      {/* Title + Description */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: showText ? 1 : 0 }}
        transition={{ duration: 0.8, delay: 0.2 }}
        className="relative z-0 flex flex-col md:flex-row md:items-end md:justify-between w-full pl-28"
      >
        <h1 className="text-3xl md:text-4xl font-bold flex items-center gap-2">
          🕰️ Explore Posts
        </h1>
        <p className="text-slate-400 text-sm md:text-base md:text-right max-w-xl mt-2 md:mt-0">
          Search and filter through various posts.
        </p>
      </motion.div>
    </div>
  )
}
